// Lazy wrapper around openscad-wasm.
// The .scad files generated by the calculator reference the original SVG by
// filename via import("foo.svg"), so we write the SVG into the WASM virtual FS
// at the same name OpenSCAD expects.

const OPENSCAD_URL = '/openscad/openscad.js';

let factoryPromise = null;
let instancePromise = null;

function loadFactory() {
  // Vite forbids `import()` against /public files from source code (even with
  // @vite-ignore). Bounce through a runtime-injected <script type="module">
  // whose inline import() Vite never analyzes. The browser still resolves the
  // URL against its real location, so import.meta.url inside openscad.js is
  // correct and its sibling .wasm.js / .wasm fetches resolve as expected.
  if (factoryPromise) return factoryPromise;
  factoryPromise = new Promise((resolve, reject) => {
    const okEvent = '__openscad_factory_ready__';
    const errEvent = '__openscad_factory_error__';
    const cleanup = () => {
      window.removeEventListener(okEvent, onOk);
      window.removeEventListener(errEvent, onErr);
    };
    const onOk = () => { cleanup(); resolve(window.__openscad_factory__); };
    const onErr = (e) => { cleanup(); reject(e.detail || new Error('Failed to load openscad-wasm')); };
    window.addEventListener(okEvent, onOk);
    window.addEventListener(errEvent, onErr);
    const script = document.createElement('script');
    script.type = 'module';
    script.textContent = `
      try {
        const m = await import(${JSON.stringify(OPENSCAD_URL)});
        window.__openscad_factory__ = m.default;
        window.dispatchEvent(new Event(${JSON.stringify(okEvent)}));
      } catch (err) {
        window.dispatchEvent(new CustomEvent(${JSON.stringify(errEvent)}, { detail: err }));
      }
    `;
    document.head.appendChild(script);
  });
  return factoryPromise;
}

async function getInstance() {
  if (!instancePromise) {
    const OpenSCAD = await loadFactory();
    instancePromise = OpenSCAD();
  }
  return instancePromise;
}

function safeUnlink(instance, path) {
  try { instance.FS.unlink(path); } catch { /* not present */ }
}

export async function renderStl(scadText, svgFilename, svgText) {
  const instance = await getInstance();

  safeUnlink(instance, '/output.stl');
  safeUnlink(instance, '/input.scad');
  safeUnlink(instance, `/${svgFilename}`);

  instance.FS.writeFile(`/${svgFilename}`, svgText);
  instance.FS.writeFile('/input.scad', scadText);

  instance.callMain(['/input.scad', '-o', '/output.stl']);

  return instance.FS.readFile('/output.stl');
}
